# 2. Last communication date 2010 onwards
# total 32370/70186
select count(*)
from tbl_companies c
where (
  select count(*)
  from tbl_communications co
  join tbl_post_initiatives pi
  on co.post_initiative_id = pi.id
  join tbl_posts p
  on p.id = pi.post_id
  where p.company_id = c.id
  and co.communication_date >= '2010-01-01'
) >= 1

# 3. Where category is..
# total 23444/70186
select count(*)
from tbl_companies c
where (
  select count(*)
  from tbl_object_tiered_characteristics otc
  join tbl_tiered_characteristics tc
  on otc.tiered_characteristic_id = tc.id
  where tc.parent_id = 0
  and tc.value in (
    'Marketing Services',
    'Healthcare Providers',
    'IT',
    'Industrial',
    'Manufacturing',
    'Pharmaceutical'
  )
  and otc.company_id = c.id
) >= 1

